+    const trustworthyOutputs = peerOutputs.filter(
+      (_, idx) => !byzantineNodes.includes(idx)
+    );
+    const trustworthyWeights = attentionWeights.filter(
+      (_, idx) => !byzantineNodes.includes(idx)
+    );
+
