+  edges: [number, number][];
+  edgeWeights: number[];
+  nodeLabels: string[];
+}
+
+interface CoordinationResult {
+  consensus: string;
+  attentionWeights: number[];
+  topAgents: AgentRanking[];
+  byzantineNodes?: number[];
